				try {
					$tw.utils.saveTiddlerToFileSync(tiddler,fileInfo);
				} catch (err) {
					result = "Error saving tiddler \"" + title + "\", to file: \"" + fileInfo.filepath + "\"";
				}
			} else {
				result = "Tiddler '" + title + "' not found";
			}
		}
	});
